### Configure Advanced Vite Settings with Plugins and Aliases for Playwright CT

Source: https://github.com/microsoft/playwright/blob/main/docs/src/test-components-js.md

Illustrates a detailed Playwright component testing configuration for Vue, demonstrating the inclusion of multiple Vite plugins (`vue`, `AutoImport`, `Components`) and path aliases. This setup allows comprehensive customization of the Vite build process within Playwright tests, such as importing global stores or components.

```js
import { defineConfig, devices } from '@playwright/experimental-ct-vue';

import { resolve } from 'path';
import vue from '@vitejs/plugin-vue';
import AutoImport from 'unplugin-auto-import/vite';
import Components from 'unplugin-vue-components/vite';

export default defineConfig({
  testDir: './tests/component',
  use: {
    trace: 'on-first-retry',
    ctViteConfig: {
      plugins: [
        vue(),
        AutoImport({
          imports: [
            'vue',
            'vue-router',
            '@vueuse/head',
            'pinia',
            {
              '@/store': ['useStore'],
            },
          ],
          dts: 'src/auto-imports.d.ts',
          eslintrc: {
            enabled: true,
          },
        }),
        Components({
          dirs: ['src/components'],
          extensions: ['vue'],
        }),
      ],
      resolve: {
        alias: {
          '@': resolve(__dirname, './src'),
        },
      },
    },
  },
});
```

